import React, { useState, useEffect } from 'react';
import {
  Container,
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  Button,
  Chip,
  CircularProgress,
  Alert,
  CardActions
} from '@mui/material';
import { motion } from 'framer-motion';
import OpenInNewIcon from '@mui/icons-material/OpenInNew';
import { api } from '../services/api';

const MotionCard = motion(Card);

const Publications = ({ featured = false }) => {
  const [publications, setPublications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchPublications = async () => {
      try {
        const response = await api.get(`/publications${featured ? '?featured=true' : ''}`);
        const data = response.data;
        setPublications(
          Array.isArray(data)
            ? data
            : data.items || data.data || []
        );
        setLoading(false);
      } catch (err) {
        setError('Failed to fetch publications');
        setLoading(false);
      }
    };

    fetchPublications();
  }, [featured]);

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" my={4}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>;
  }

  return (
    <Container maxWidth="lg" sx={{ py: 8 }}>
      <Typography variant="h2" component="h1" gutterBottom align="center">
        Publications
      </Typography>
      <Typography
        variant="h5"
        color="text.secondary"
        paragraph
        align="center"
        sx={{ mb: 6 }}
      >
        Articles and technical publications
      </Typography>

      <Grid container spacing={4}>
        {publications.map((publication) => (
          <Grid item key={publication._id} xs={12} sm={6} md={4}>
            <Card
              sx={{
                height: '100%',
                display: 'flex',
                flexDirection: 'column'
              }}
            >
              <CardContent sx={{ flexGrow: 1 }}>
                <Typography gutterBottom variant="h5" component="h2">
                  {publication.title}
                </Typography>
                <Typography variant="subtitle1" color="text.secondary" gutterBottom>
                  {publication.journal}
                </Typography>
                <Typography variant="body2" color="text.secondary" gutterBottom>
                  Published: {new Date(publication.publicationDate).toLocaleDateString()}
                </Typography>
                <Typography variant="body1" paragraph>
                  {publication.abstract}
                </Typography>
                <Box mt={2}>
                  {publication.keywords.map((keyword) => (
                    <Chip
                      key={keyword}
                      label={keyword}
                      size="small"
                      sx={{ mr: 1, mb: 1 }}
                    />
                  ))}
                </Box>
              </CardContent>
              <CardActions>
                {publication.doi && (
                  <Button
                    size="small"
                    color="primary"
                    href={`https://doi.org/${publication.doi}`}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    View Paper
                  </Button>
                )}
                {publication.pdfUrl && (
                  <Button
                    size="small"
                    color="primary"
                    href={publication.pdfUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    Download PDF
                  </Button>
                )}
              </CardActions>
            </Card>
          </Grid>
        ))}
      </Grid>
    </Container>
  );
};

export default Publications;
